package org.apache.commons.csv;

import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.when;

@ExtendWith(MockitoExtension.class)
public class CSVFormatTest {

    @Mock
    CSVFormat csvFormat;

    @Test
    public void testGetSkipHeaderRecord() throws Exception {
        // Given
        boolean expectedSkipHeaderRecord = true;
        when(csvFormat.getSkipHeaderRecord()).thenReturn(expectedSkipHeaderRecord);

        // When
        boolean actualSkipHeaderRecord = csvFormat.getSkipHeaderRecord();

        // Then
        assertEquals(expectedSkipHeaderRecord, actualSkipHeaderRecord);
    }
}
